sp_widget.client_script:
api.controller=function ($scope, $rootScope, amb, $timeout) {
	/* widget controller */
	var c = this;
  $scope.submitting = false;
  $scope.mandatory = [];
  $scope.errorMessages = [];
  $scope.data.show_sql = false;
	var g_form;

	angular.element('.modal-footer').css({display:'none'});

	$scope.initiatingTemplate = false;
	$scope.templateStarted = false;
	$scope.btnCancelClick = function(){
		// close modal window
		$scope.$parent.buttonClicked($scope.$parent.options.buttons[0]);
	};

	$scope.lnkTaskOpenClick = function(){
		// close modal window
		$scope.$parent.buttonClicked($scope.$parent.options.buttons[0]);
	};

	$scope.btnGenderateDraftButton = function(){
		startTemplate('generate_draft');
	};

	$scope.btnStartButton = function(){
		startTemplate('start_template');
	};

	function startTemplate(action){
		// STRY0100724: DEV Story- Performance Improvements -  Running Templates and implify
		$scope.$evalAsync(function() {
			if(g_form){
				$scope.submitting = true;
				if(g_form.submit(action)){
					$scope.initiatingTemplate = true;
					$(".showAlert").hide().show('medium');
					var table = 'x_153465_discovert_route_task_instance';
					var filter = 'u_parent_template='+ c.data.process_template_sys_id + '^parentISEMPTY';
					// Start watching for task looking for an event for the Template ID before starting the template
					if (c.watcher)
						c.watcher.unsubscribe();
					c.watcher = watcher(table, filter, taskFromTemplateStarted);
					return;
				}
				$scope.submitting = false;
			}
		});		
	}

	// Make sure to include amb as a provider in your client controller
	// function to setup a watcher
	function watcher(table, filter, callback){
		var channel = amb.getChannelRW(table, filter);
		amb.connect();
		var watch = channel.subscribe(callback);
		return watch;
	}

	function taskFromTemplateStarted(message){
		// STRY0113838
		var pageId = 'discovertasker_taskdetails';
		var pageTable = c.data.table;
		c.data.getURL=true;
		c.data.sys_id=message.data.sys_id;
		c.data.view ='sp';
		$scope.server.update().then(function(data) {
			// DFCT0011134
			c.data.linkToTopTaskForTemplateStarted = '../' + data.portal_url_ref + 
				'?id=' + data.pageId + '&table=x_153465_discovert_route_task_instance' +
				'&sys_id=' + data.sys_id + '&view=' + data.view + '&spa=1';
			c.data.taskDisplayValue = message.data.display_value;
			$scope.initiatingTemplate = false;
			$scope.templateStarted = true;
		});

		// done with record watcher unsubscribe	
		c.watcher.unsubscribe();
	}

	$scope.$on('spModel.fields.rendered', function() {
		if (c.panels)
			c.panels.removeClass('shift-out').addClass('shift-in');
	});

	function initForm(gFormInstance) {
		if (gFormInstance.getTableName() != undefined &&
				gFormInstance.getTableName() == $scope.data.f.table) {
			g_form = gFormInstance;
			// was a javascript error.  _save is not in this form
			// spNavStateManager.register($scope.data.table, _save, g_form);
			$scope.isPageReady = true;
			$timeout(function() {
				$rootScope.$emit('spModel.gForm.rendered', g_form);
			}, 175);

		}
	}

  $scope.$on('spModel.gForm.initialized', function(e, gFormInstance) {
		initForm(gFormInstance);
  });

	$scope.$on('spModel.gForm.env.created', function(e, gFormInstance) {
		initForm(gFormInstance);
	});

	// remove record watcher when form closes
	$scope.$on('$destroy', function() {
		if (c.watcher)
			c.watcher.unsubscribe();
	});

  function clearStatus() {
    $scope.status = "";
  }

};

sp_widget.css:
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES 
//------------------------------------------------------------------------------------------------------------------------
//------------------------------------------------------------------------------------------------------------------------
// 2.5.21 | 09.10.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
//------------------------------------------------------------------------------------------------------------------------


//------------------------------------------------------------------------------------------------------------------------
// CUSTOM
//------------------------------------------------------------------------------------------------------------------------


/* SECTIONS & FORMS */
//------------------------------------------------------------------------------------------------------------------------
.ng-isolate-scope .h4.ng-binding{
  font-weight: 400 !important;
  font-family: "SourceSansPro", Helvetica, Arial, sans-serif; //'Lucida Sans Unicode';
  padding-left: 5px;
	border-left-style: solid;
	border-left-color: $primary;
	border-left-width: 5px;
	color: $primary;
	padding-top: 8px;
	padding-bottom: 5px;
}

fieldset.ng-scope{
  margin-top: 5px;
}

label{
	//font-weight: 100!important;
  color: $primary;
}


/* DURATION */
//------------------------------------------------------------------------------------------------------------------------

#dur-minutes,
#dur-seconds { 
  visibility: hidden!important;
}

#dur-days,
#dur-hours { 
  width: 40px!important
}


//------------------------------------------------------------------------------------------------------------------------
// OOTB FORM WIDGET
//------------------------------------------------------------------------------------------------------------------------


.btn-form-menu {
	vertical-align: inherit;
  padding: inherit;
  background: none;
}

.panel-title {
  word-wrap: break-word;
}

.panel-heading {
  .dropdown-menu {
    a {
      white-space: normal;
    }
  }
}

/*
2.7.0 | 2021-10-29 | mmcc | STRY0110472 - Stretch- 508 Compliant- Delete Buttons- (ALL Red buttons)
.dtech-field-error-label {} replaces below; Find it in Tasker Theme > Tasker Form Error Overrides Style Sheet
.sc-field-error-label {
  margin-right: .5em;
  display: inline-block;
  background-color: $sc-field-error-color;
}
*/

.comment {
	font-weight: bold;
	margin-top: 2px;
	margin-bottom: 2px;
}
.mce-panel, .mce-btn {
	background-image: none;
	background-color: #f0f3f4;
}

.action-btn {
  margin-right: 5px;
}

.timeline-container {
   max-height: 50vh;
   height: 100%;
   overflow-y: auto;
}

.panel .panel {
    height: auto !important;
}

.attachment-button {
  .glyphicon-paperclip {
    font-size: 18px;
  }
}

.dropdown {
  .glyphicon-menu-hamburger:focus {
 		outline: thin dotted;
		outline: 5px auto $input-border-focus;
		outline-offset: -2px; 
	}
}

.empty-state-wrapper {
  width: 100%;
  height: 100%;
  align-items: center;
  display: flex;
  flex-direction: column;
  padding: 10vh 20px 20px;

  .empty-state {
    border: 1px solid #e7e9eb;
    border-radius: 10px;
    max-width: 700px;
    padding: 30px 40px 20px;
    position: relative;

    .empty-state-badge {
      top: -36px;
      left: 50%;
      position: absolute;
      height: 72px;
      width: 72px;
      -webkit-align-items: center;
      -ms-flex-align: center;
      align-items: center;
      border-radius: 100%;
      color: #ffffff;
      display: -webkit-flex;
      display: -ms-flexbox;
      display: flex;
      font-size: 40px;
      -webkit-justify-content: center;
      -ms-flex-pack: center;
      justify-content: center;
      margin-left: -36px;
      text-align: center;
    }

    .empty-state-header {
      font-size: 30px;
      text-align: center;
      color: #343d47;
    }

    .empty-state-content {
      ul {
        list-style: disc outside;
        margin: 0 0 10px 0;
        padding: 0 0 0 30px;
      }
    }
  }
}

.text-success-alt {
	background-color: $state-success-text;
}

.text-info-alt {
	background-color: $state-info-text;
}

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// WIDGET BASE: TASKER DATA TABLE
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: Karina Torres
/**
 * Description
 * This widget opens when you click on "Run Process Template" 
 * @method anonymous-0
 * @author Karina Torres [KTorres]
 * @memberof x_153465_discovert.module:sp_widget
 * @returns {undefined}
 */
//------------------------------------------------------------------------------------------------------------------------
//
// 2.7.0 | 07.05.2021 | raj | STRY0100724: DEV Story- Performance Improvements -  Running Templates and implify
//                                   Updates in Server, Client and HTML
// 2.7.0 | 2021-08-10 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
// 											In CSS, selector .taskform-classification-banner removed, not used. 
// 											 Selector .assignmentgroup-banner removed, not used.
//											 Selector #sp_formfield_status removed, was commented out.
//											In Server script, fixed white space issues, format whole script.
//                                          Changes in CSS and Server script
// 2.7.0 | 2021-10-29 | mmcc | STRY0110472 - Stretch- 508 Compliant- Delete Buttons- (ALL Red buttons)
//											In HTML, CSS selector .sc-field-error-label changed to .dtech-field-error-label
//											In CSS, added place holder for .dtech-field-error-label to go to theme.
//                                          Changes in HTML and CSS
// 2.7.0 | 2021-10-230 | raj | STRY0113375 - Draft from Templates Update- UI- Add "Draft Template" Action Button
//											In HTML,updated button text and hover
//											In client script add new button for generate draft tasks
//											NOTE: caption and hover should pick up from UI Actions, but don't
// 2.7.0 | 2021-11-16 | raj  | STRY0113838 - Tasker Settings- Allow for custom "URL Suffix" for Tasker Portal
//                                         Changes made in Client Script
// 2.7.1 | 2021-12-11 | raj | DFCT0010669 - Tasks in Banner notifications does NOT redirect to the correct portal page configured in "Task Form Preference" 
// 2.8.0 | 2022-08-13 | raj  | STRY0126024 - Templates- Add Classification/Restricted Group Ribbons on Template Forms
//																			Changes in Server Script and HTML
// 2.8.0 | 2022-08-13 | raj  | DFCT0011134 - Draft Tasks form should NOT display Section header "Task Form", "Task Tree label text and field". Subtasks table columns name are NOT displaying correctly
//                             changes in Client Controller in URL setting of the view
// 2.8 | 2022-09-26 | mmcc | DFCT0011365 - On the "Template Instance", "Classification ribbon" for the generic color for custom Classifications does NOT display
//                                      In HTML, add CSS Selector .taskform-classification-banner-default for Classification
//                                      Changes made in HTML.
// 2.8 | 2022-10-19 | mmcc | STRY0130862 - Run Template Modal needs updated to match the standard layout for flexing header-body-footer 
//                                      In HTML, updated CSS selectors panel-shift, panel panel-default and panel-body to use flex CSS.
//                                        Updated <sp-model> to style oveflow, gutter and padding.
//                                      In Client controller, added many missing semicolons.
//                                        Removed used references spAriaFocusManager, $http, spUtil, $location, $window,  
//                                      nowAttachmentHandler, $log, spAriaUtil, spModal, $uibModal, spNavStateManager.
//                                      Changes made in HTML and Client controller.
// 2.8.1 | 2022-12-09 | mmcc | STRY0133733 - 2.8.1 Tech Debt - Update Tasker App to set CSS Style for Classification based on Value
//                                      In HTML, for top Ribbon changed taskform-classification-banner- to use {{data.classificationValue}}
//                                      In Server script, added data.classificationValue set with ._fields.classification.value
//                                      Changes made in HTML and Server script.
//
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options, gs) {
    /* populate the 'data' object */

		data.omitHeaderOptions = (input || {}).omitHeaderOptions || (options || {}).omitHeaderOptions;	
		data.omitHeader = (input || {}).omitHeader || (options || {}).omitHeader;	

    // STRY0098385 - remove Cancel button from Mobile 
    data.page_id = $sp.getParameter("id");

    // rebuild the widget to run using template instance
    // RJ - TUP - STRY0068618 
    // STRY0090951 - Mobile – Run Template action from swipe action and from UI action on Template form
    data.process_template_sys_id = (input || {}).process_template_sys_id || (options || {}).process_template_sys_id || $sp.getParameter('process_template_sys_id');
    // STRY0090951 - Mobile – Run Template action from swipe action and from UI action on Template form
    if (input == undefined  || (!input.templateStarted && !input.initiatingTemplate) ) {
        data.canAttach = false;
        // build the Template Instance Form here
        data.f = $sp.getForm("x_153465_discovert_discover_routing_runtime",
            "-1", 'routing_template_ref=' + data.process_template_sys_id,
            "Default View");
				// STRY0126024
				if(data.f._fields.classification){
					data.classification = data.f._fields.classification.displayValue;
					// 2.8.1 | 2022-12-09 | mmcc | STRY0133733 - Update Tasker App to set CSS Style for Classification based on Value
					data.classificationValue = data.f._fields.classification.value;
				}
				if(data.f._fields.u_restricted_group){
					data.restrictedGroup = data.f._fields.u_restricted_group.displayValue;
				}
        data.canRun = new uiConditionCheck().startTemplateUIAction(data.process_template_sys_id, '');
    }

		// STRY0113838
		if (input && input.getURL==true){
			// DFCT0010669
			var oUserPref = new x_153465_discovert.tasker_User_Form_Preferences();
			data.userPreferences = oUserPref.loadMyFormPreferences();

			// if just getting the URL, then get URL and return
			var url_Properties = oUserPref.get_URL_Properties_for_Task_Based_on_Prefrences(input.sys_id,input.view);
			data.sys_id = input.sys_id;
			data.pageId = url_Properties.pageId;
			data.pageTable = url_Properties.pageTable;
			data.view = url_Properties.view;
			data.portal_url_ref = url_Properties.portal_url_ref;
			// only call once
			data.getURL = false;
			return;
		}	

})($sp, input, data, options, gs);
